    - name : String
}
class File {
}
class Folder {
}
class Access {
    - canView : Boolean
    - canEdit : Boolean
}
class AncestorLink {
    - degree : Integer
}
Person "0..*" -- "0..1"  Person : ParentOf
Person "0..*" -- "1"  AncestorLink : HasAncestorLink
User "0..*" -- "1"  Access : HasAccess
Resource "0..*" -- "1"  Access : IsAccessibleBy
Folder "0..*" *-- "0..1"  Resource : Folder_Contains_Resource
Person <|-- User
Resource <|-- File
Resource <|-- Folder
@enduml

